import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Search, MapPin, Wind, Droplets, Gauge, Eye, Sun, Cloud, CloudRain, CloudLightning, Snowflake, History, Download, Trash2, X, ChevronRight, Thermometer } from 'lucide-react';
import api from '../services/api';

const WeatherApp = () => {
    const [query, setQuery] = useState('');
    const [weather, setWeather] = useState(null);
    const [forecast, setForecast] = useState([]);
    const [history, setHistory] = useState([]);
    const [suggestions, setSuggestions] = useState([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [showHistory, setShowHistory] = useState(false);

    const fetchWeather = async (params) => {
        setLoading(true);
        setError(null);
        try {
            const response = await api.getWeather(params);
            setWeather(response.data.weather);
            setForecast(response.data.forecast);

            await api.saveToHistory({
                location: response.data.location,
                weather: response.data.weather,
                forecast: response.data.forecast
            });
            loadHistory();
            setSuggestions([]);
            setQuery('');
        } catch (err) {
            setError(err.response?.data?.error || 'Failed to fetch weather');
        } finally {
            setLoading(false);
        }
    };

    const loadHistory = async () => {
        try {
            const response = await api.getHistory();
            setHistory(response.data);
        } catch (err) {
            console.error('Failed to load history', err);
        }
    };

    const deleteHistory = async (id) => {
        try {
            await api.deleteHistory(id);
            loadHistory();
        } catch (err) {
            console.error('Delete history error', err);
        }
    };

    const debounce = (func, delay) => {
        let timeout;
        return (...args) => {
            clearTimeout(timeout);
            timeout = setTimeout(() => func(...args), delay);
        };
    };

    const getSuggestions = useCallback(
        debounce(async (q) => {
            if (q.length < 2) {
                setSuggestions([]);
                return;
            }
            try {
                const response = await api.searchLocations(q);
                setSuggestions(response.data);
            } catch (err) {
                console.error('Searching error', err);
            }
        }, 500),
        []
    );

    useEffect(() => {
        if (query) getSuggestions(query);
        else setSuggestions([]);
    }, [query, getSuggestions]);

    useEffect(() => {
        navigator.geolocation.getCurrentPosition(
            (pos) => fetchWeather({ lat: pos.coords.latitude, lon: pos.coords.longitude }),
            () => fetchWeather({ city: 'London' })
        );
        loadHistory();
    }, []);

    const getWeatherIcon = (condition, size = 24) => {
        const cond = condition.toLowerCase();
        if (cond.includes('clear')) return <Sun size={size} className="text-yellow-400" />;
        if (cond.includes('cloud')) return <Cloud size={size} className="text-blue-200" />;
        if (cond.includes('rain')) return <CloudRain size={size} className="text-blue-400" />;
        if (cond.includes('thunder')) return <CloudLightning size={size} className="text-purple-400" />;
        if (cond.includes('snow')) return <Snowflake size={size} className="text-white" />;
        return <Cloud size={size} />;
    };

    return (
        <div className="min-h-screen p-4 md:p-8 flex flex-col items-center">
            {/* Search Header */}
            <motion.div
                initial={{ y: -50, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                className="w-full max-w-4xl flex items-center gap-4 mb-12 relative z-50"
            >
                <div className="flex-1 relative">
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                        <Search size={20} />
                    </div>
                    <input
                        type="text"
                        className="input-glass pl-12 pr-4"
                        placeholder="Search city, ZIP, or country..."
                        value={query}
                        onChange={(e) => setQuery(e.target.value)}
                    />

                    <AnimatePresence>
                        {suggestions.length > 0 && (
                            <motion.div
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: 10 }}
                                className="absolute top-full mt-2 w-full glass-card p-2 overflow-hidden"
                            >
                                {suggestions.map((s, i) => (
                                    <motion.div
                                        key={i}
                                        whileHover={{ x: 10, backgroundColor: 'rgba(255,255,255,0.05)' }}
                                        className="p-3 cursor-pointer rounded-xl flex items-center justify-between group"
                                        onClick={() => fetchWeather({ city: s.name })}
                                    >
                                        <span>{s.name}, {s.state && `${s.state}, `}{s.country}</span>
                                        <ChevronRight size={16} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                                    </motion.div>
                                ))}
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>

                <button
                    onClick={() => setShowHistory(true)}
                    className="glass-card p-4 hover:bg-white/10 transition-colors"
                >
                    <History size={20} />
                </button>
            </motion.div>

            {/* Main Weather Display */}
            <div className="w-full max-w-6xl grid grid-cols-1 lg:grid-cols-3 gap-8">

                {/* Hero Current Weather */}
                <AnimatePresence mode="wait">
                    {weather && (
                        <motion.div
                            key={weather.description + weather.temperature}
                            initial={{ scale: 0.9, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            exit={{ scale: 0.9, opacity: 0 }}
                            className="lg:col-span-2 glass-card p-8 flex flex-col justify-between min-h-[400px] relative overflow-hidden group"
                        >
                            <div className="absolute top-0 right-0 p-8 opacity-20 group-hover:opacity-40 transition-opacity duration-700">
                                {getWeatherIcon(weather.condition, 200)}
                            </div>

                            <div className="z-10">
                                <div className="flex items-center gap-2 text-slate-400 mb-4">
                                    <MapPin size={18} />
                                    <span className="text-lg font-medium">Current Location</span>
                                </div>
                                <h1 className="text-5xl md:text-7xl font-bold mb-2 heading">
                                    {Math.round(weather.temperature)}°
                                </h1>
                                <p className="text-xl text-slate-300 capitalize flex items-center gap-2">
                                    {getWeatherIcon(weather.condition, 24)}
                                    {weather.description}
                                </p>
                            </div>

                            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-12 z-10">
                                <div className="bg-white/5 rounded-2xl p-4">
                                    <span className="text-xs text-slate-400 block mb-1">FEELS LIKE</span>
                                    <div className="flex items-center gap-2">
                                        <Thermometer size={16} />
                                        <span className="font-semibold">{Math.round(weather.feelsLike)}°</span>
                                    </div>
                                </div>
                                <div className="bg-white/5 rounded-2xl p-4">
                                    <span className="text-xs text-slate-400 block mb-1">HUMIDITY</span>
                                    <div className="flex items-center gap-2">
                                        <Droplets size={16} />
                                        <span className="font-semibold">{weather.humidity}%</span>
                                    </div>
                                </div>
                                <div className="bg-white/5 rounded-2xl p-4">
                                    <span className="text-xs text-slate-400 block mb-1">WIND</span>
                                    <div className="flex items-center gap-2">
                                        <Wind size={16} />
                                        <span className="font-semibold">{weather.windSpeed} km/h</span>
                                    </div>
                                </div>
                                <div className="bg-white/5 rounded-2xl p-4">
                                    <span className="text-xs text-slate-400 block mb-1">PRESSURE</span>
                                    <div className="flex items-center gap-2">
                                        <Gauge size={16} />
                                        <span className="font-semibold">{weather.pressure} hPa</span>
                                    </div>
                                </div>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>

                {/* 5-Day Forecast Grid */}
                <div className="flex flex-col gap-4">
                    <h3 className="text-xl font-bold px-2 flex items-center gap-2">
                        <Sun size={20} className="text-primary" />
                        5-Day Forecast
                    </h3>
                    <div className="flex flex-col gap-4 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
                        {forecast.map((day, i) => (
                            <motion.div
                                key={i}
                                initial={{ x: 50, opacity: 0 }}
                                animate={{ x: 0, opacity: 1 }}
                                transition={{ delay: i * 0.1 }}
                                whileHover={{ y: -5 }}
                                className="glass-card p-4 flex items-center justify-between"
                            >
                                <div className="flex flex-col">
                                    <span className="text-sm font-medium text-slate-200">
                                        {new Date(day.date).toLocaleDateString('en-US', { weekday: 'short' })}
                                    </span>
                                    <span className="text-xs text-slate-400">
                                        {new Date(day.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                                    </span>
                                </div>
                                <div className="flex items-center gap-3">
                                    {getWeatherIcon(day.condition, 24)}
                                    <div className="flex flex-col items-end">
                                        <span className="font-bold">{Math.round(day.temperature.max)}°</span>
                                        <span className="text-xs text-slate-400">{Math.round(day.temperature.min)}°</span>
                                    </div>
                                </div>
                            </motion.div>
                        ))}
                    </div>
                </div>
            </div>

            {/* History Sidebar */}
            <AnimatePresence>
                {showHistory && (
                    <>
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setShowHistory(false)}
                            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100]"
                        />
                        <motion.div
                            initial={{ x: '100%' }}
                            animate={{ x: 0 }}
                            exit={{ x: '100%' }}
                            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                            className="fixed right-0 top-0 bottom-0 w-full max-w-md bg-[#0f0f12] border-l border-white/10 p-8 z-[101] shadow-2xl"
                        >
                            <div className="flex items-center justify-between mb-8">
                                <h2 className="text-2xl font-bold heading">Recent Searches</h2>
                                <button onClick={() => setShowHistory(false)} className="hover:bg-white/10 p-2 rounded-full transition-colors">
                                    <X size={24} />
                                </button>
                            </div>

                            <div className="flex flex-col gap-4 overflow-y-auto h-[calc(100vh-250px)] pr-2">
                                {history.length === 0 ? (
                                    <p className="text-slate-500 text-center mt-12">No history yet</p>
                                ) : (
                                    history.map((item) => (
                                        <div key={item._id} className="glass-card p-4 group">
                                            <div className="flex items-center justify-between mb-2">
                                                <span className="font-semibold">{item.location.name}</span>
                                                <button
                                                    onClick={() => deleteHistory(item._id)}
                                                    className="opacity-0 group-hover:opacity-100 text-rose-500 hover:bg-rose-500/10 p-2 rounded-lg transition-all"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                            <div className="flex items-center gap-4 text-sm text-slate-400">
                                                <span className="flex items-center gap-1">
                                                    {getWeatherIcon(item.weather.condition, 16)}
                                                    {Math.round(item.weather.temperature)}°
                                                </span>
                                                <span>{new Date(item.searchDate).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>

                            <div className="absolute bottom-8 left-8 right-8 flex gap-4">
                                <button
                                    onClick={async () => {
                                        const res = await api.exportHistory();
                                        const blob = new Blob([JSON.stringify(res.data, null, 2)], { type: 'application/json' });
                                        const url = URL.createObjectURL(blob);
                                        const a = document.createElement('a');
                                        a.href = url;
                                        a.download = 'weather_history.json';
                                        a.click();
                                    }}
                                    className="flex-1 btn-primary flex items-center justify-center gap-2"
                                >
                                    <Download size={18} />
                                    Export Data
                                </button>
                            </div>
                        </motion.div>
                    </>
                )}
            </AnimatePresence>

            <footer className="mt-auto pt-16 pb-8 text-slate-500 text-sm flex flex-col items-center gap-2">
                <div className="flex items-center gap-4">
                    <a href="#" className="hover:text-white transition-colors">Documentation</a>
                    <span>•</span>
                    <a href="#" className="hover:text-white transition-colors">API Status</a>
                    <span>•</span>
                    <a href="#" className="hover:text-white transition-colors">Support</a>
                </div>
                <p>© 2026 WeatherApp Premium • Created by Om Joshi</p>
            </footer>
        </div>
    );
};

export default WeatherApp;
