import axios from 'axios';

const API_BASE_URL = 'http://localhost:5000/api';

const api = {
    getWeather: (params) => axios.get(`${API_BASE_URL}/weather`, { params }),
    searchLocations: (q) => axios.get(`${API_BASE_URL}/weather/search`, { params: { q } }),
    saveToHistory: (data) => axios.post(`${API_BASE_URL}/weather`, data),
    getHistory: () => axios.get(`${API_BASE_URL}/history`),
    deleteHistory: (id) => axios.delete(`${API_BASE_URL}/weather/${id}`),
    exportHistory: () => axios.get(`${API_BASE_URL}/export`)
};

export default api;
